<template><section class="page-pad"><div class="mb-6"><h1 class="text-3xl font-black">المصروفات</h1><p class="text-muted mt-2">تسجيل مصروفات المعرض وربطها بالخزنة والتقارير</p></div><div class="card p-5 mb-6"><div class="form-grid"><input v-model="form.title" class="input" placeholder="عنوان المصروف"><input v-model.number="form.amount" class="input" placeholder="المبلغ"><select v-model="form.currency" class="input"><option value="IQD">دينار عراقي</option><option value="USD">دولار</option></select><select v-model="form.category" class="input"><option>وقود</option><option>صيانة</option><option>رواتب</option><option>إيجار</option><option>تسويق</option><option>عام</option></select><input v-model="form.notes" class="input" placeholder="ملاحظات"><button class="btn-primary btn" @click="add">إضافة مصروف</button></div></div><div class="card overflow-x-auto"><table class="table"><thead><tr><th>العنوان</th><th>المبلغ</th><th>التصنيف</th><th>التاريخ</th><th>ملاحظات</th></tr></thead><tbody><tr v-for="e in data" :key="e.id"><td class="font-black">{{e.title}}</td><td>{{money(e.amount,e.currency)}}</td><td>{{e.category}}</td><td>{{dateText(e.expenseDate)}}</td><td>{{e.notes || '-'}}</td></tr></tbody></table></div></section></template>
<script setup lang="ts">
const { data, refresh } = useLazyFetch<any[]>('/api/expenses')
const form=reactive({title:'',amount:0,currency:'IQD',category:'عام',notes:''})
async function add(){ await $fetch('/api/expenses',{method:'POST',body:form}); Object.assign(form,{title:'',amount:0,currency:'IQD',category:'عام',notes:''}); refresh() }
</script>
